<script setup>import {computed} from 'vue'import {useRouter} from 'vue-router'import trashBin from '@/assets/images/trash-bin.svg'const router = useRouter()const props = defineProps({  todolist: {    type: Array,    required: true,    default: () => [],  },  search: {    type: String,    default: '',  }}) const emit = defineEmits(['delete-todo'])// 검색어 기준 필터링const filteredTodos = computed(() => {  const keyword = props.search.trim().toLowerCase()  if (!keyword) return props.todolist  return props.todolist.filter(todo =>    String(todo.title ?? '').toLowerCase().includes(keyword)  )})// 삭제 이벤트 const onDelete = (id) => {  emit('delete-todo', id)  console.log('자식 컴포넌트에서 삭제 이벤트 보냄')}// 상세페이지 이동 이벤트const goDetail = (id) => {  router.push(`/todo/${id}`)}</script><template>  <ul class ="rows">    <!-- 필터링 전 todo list.만 출력 -->    <li v-for="todo in filteredTodos" :key="todo.id" class="row"      @click="goDetail(todo.id)">        <div class="col title">{{todo.title}}</div>        <div class="col author">{{todo.author}}</div>        <div class="col date">{{todo.createdAt}}</div>        <div class="col actions">          <button class="removeBtn" type="button" @click.stop="onDelete(todo.id)">            <img class="trash" :src="trashBin" alt="삭제" />          </button>        </div>        </li>  </ul></template><style lang="css" scoped>/* 리스트 전체 형태 */.rows {  list-style: none;  padding: 0;  margin: 0;}/* 가로 한 줄 블록 */.row {  display: flex;  flex-direction: row;  align-items: center;  flex-wrap: nowrap;      /* 줄바꿈 방지 */  gap: 16px;  padding: 12px 16px;  margin-bottom: 10px;  background: #fff;  border-radius: 10px;  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.06);}/* 상세 페이지 이동 시 가로 블록 cursor */.row {  cursor: pointer;}.row:hover {  background: #f9fafb;}.col {  min-width: 0;           /* ellipsis(길어질 시 생략)를 위해 중요 */  font-size: 14px;  white-space: nowrap;}/* 컬럼 비율 */.title {  flex: 2 1 0;  font-weight: 600;  overflow: hidden;  text-overflow: ellipsis;}.author {  flex: 1;  color: #555;}.date {  flex: 1;  color: #777;}/* 삭제 버튼 css */ .actions {  margin-left: auto;  display: flex;  align-items: center;}.removeBtn {  background: transparent;  border: none;  padding: 4px;  cursor: pointer;  display: flex;  align-items: center;}.trash {  width: 16px;  height: 16px;  opacity: 0.6;  transition: opacity 0.2s ease, transform 0.2s ease;}.removeBtn:hover .trash {  opacity: 1;  transform: scale(1.1);}  </style>